async function HandleOnLoadEvent(n){var e="https://worker-winter-glade-cd02.bigtentgames.workers.dev/"+encodeURIComponent(window.location.search.split("?")[1]);await fetch(e,{headers:{Host:window.location.hostname,Origin:window.location.origin}}).then((n=>{if(!n.ok)throw new Error("Server error: "+n.status);return n.text()})).then((n=>{location.href=location.origin+"/"+n})).catch((n=>{}))}window.addEventListener("load",HandleOnLoadEvent);